/***** AUTO-DETECT HEADERS (case/space/nbsp tolerant) *****/
const headerAliases = {
  scene: ['scene number','scene','scene no','scenenumber','scene_no'],
  narr:  ['narration','narr','voice over','vo','narration (en)'],
  tos:   ['text on screen','text-on-screen','on screen text','screen text','tos','caption','subtitle','text on screen']
};

const normalizeKey = s => (s ?? '')
  .toString()
  .replace(/\u00A0/g,' ')
  .replace(/\s+/g,' ')
  .trim()
  .toLowerCase();

const first = $('Edit Fields3').first().json;
const allKeys = Object.keys(first);

function findKey(aliases){
  for (const k of allKeys){
    const nk = normalizeKey(k);
    for (const a of aliases) if (nk === normalizeKey(a)) return k;
  }
  for (const k of allKeys){
    const nk = normalizeKey(k);
    for (const a of aliases) if (nk.includes(normalizeKey(a))) return k;
  }
  return null;
}

const COL_SCENE = findKey(headerAliases.scene) || 'Scene number';
const COL_NARR  = findKey(headerAliases.narr)  || 'Narration';
const COL_TOS   = findKey(headerAliases.tos)   || 'Text on screen';


/***** CLEAN VALUE HELPER *****/
const clean = s => (s ?? '')
  .toString()
  .replace(/\r\n?/g,'\n')
  .trim();


/***** COLLECT ALL ROWS *****/
const rows = $items('Edit Fields3').map((it, i) => {
  const j = it.json || {};
  return {
    id: i + 1,
    scene: clean(j[COL_SCENE]),
    narr:  clean(j[COL_NARR]),
    tos:   clean(j[COL_TOS]),
  };
});


/***** BUILD TAGGED BODY (THIS IS YOUR TRANSLATION CONTENT) *****/
const body = rows.map(r => `
⟦S${r.id}⟧
SCENE: ${r.scene || r.id}
NARR: ${r.narr}
TOS: ${r.tos}
⟦/S${r.id}⟧
`).join('\n');


/***** WEBHOOK VALUES *****/
const subject = $('Webhook1').first().json.body.subject;
const grade   = $('Webhook1').first().json.body.grade;
const referenceBox = $('Webhook1').first().json.body.referenceText|| "";


/***** FULL PROMPT (YOUR EXACT INSTRUCTIONS + CONTENT) *****/
const prompt = `
📘 Expert Academic Curator & Translator (Hindi)

Role: You are an Expert Academic Curator. Your goal is to produce a flawless, educationally sound Hindi learning module that prioritizes factual and scientific correctness over literal translation.

1. Core Principles: Accuracy & Correction
Correctness Over Literalism: Fix any factual, scientific, logical, or numerical errors found in the English source. Translate the intended meaning, not the mistake.
NCERT Compliance: Strictly follow NCERT syllabus standards. Use the provided "Reference" input to determine specific vocabulary and terminology before translating.
Pedagogical Terms: Use formal academic terms (e.g., use अधिगम (Adhigam) instead of informal/AI-style words).
Strictly follow NCERT syllabus standards.
Use the following Reference Box terminology as authoritative:

Reference Box:
${referenceBox}

2. Formatting & Structure (Strict)
Sentence Correspondence: Maintain a strict 1:1 ratio. Do NOT merge, split, skip, or add sentences.
Translate every word exactly as given. Do not omit, skip, summarize, paraphrase, or add any extra words. Preserve the complete original structure and meaning.
Tag Preservation: Do NOT modify, translate, or reorder tags (e.g., ⟦S#⟧, PBRK_...). Translate only the text between them.
Output Only: Provide only the final translated content. No explanations or notes.

3. Language & Tone
Teacher’s Voice: Use clear, natural, and idiomatic Hindi as if a subject expert is explaining to a student.
Simplicity: Use short sentences suitable for the specified grade level.
Grammar: Follow standard Hindi SOV order.

4. Symbols, Units & Technical Rules (No Translation)
Preserve English Format: Keep all units, variables, equations, and formulas exactly as they appear.
Logarithms & SS': Keep entirely in English.
No English in Brackets.
Use correct academic transliteration.

---------------------------------------

Subject: ${subject}
Grade: ${grade}

Content to be translated:
${body}
`;

/***** BUILD META FOR LATER NODE *****/
const segIdForRow = {};
rows.forEach((r, i) => {
  segIdForRow[i] = r.id;   // map row index → segment id
});


return [{
  json: {
    contents: [
      {
        role: "user",
        parts: [{ text: prompt }]
      }
    ],

    meta: {
      rows,
      segIdForRow,
      uniqCount: rows.length
    }
  }
}];

// n8n Code node (JavaScript)
// OUTPUT: one item per scene
// Works with Gemini / AI Agent different response structures

// =============================
// HELPER
// =============================
function cleanValue(v) {
  if (v == null) return "";
  let s = String(v).trim();

  if (/^n\/a\b/i.test(s)) return "";
  if (/^na\b/i.test(s)) return "";

  return s.replace(/[ \t]+$/g, "");
}

// =============================
// READ INPUT (AUTO DETECT)
// =============================
let raw =
  items?.[0]?.json?.parts?.[0]?.text ||
  items?.[0]?.json?.candidates?.[0]?.content?.parts?.[0]?.text ||
  items?.[0]?.json?.response?.parts?.[0]?.text ||
  items?.[0]?.json?.output ||
  "";

// force string
raw = String(raw);

// convert literal "\n" → real new lines
raw = raw.replace(/\\n/g, "\n");

raw = cleanValue(raw);

// stop if empty
if (!raw) return [];

// =============================
// MATCH SCENE BLOCKS
// ⟦S1⟧ ... ⟦/S1⟧
// =============================
const blockRegex = /⟦S(\d+)⟧([\s\S]*?)⟦\/S\1⟧/g;

const scenes = [];
let match;

while ((match = blockRegex.exec(raw)) !== null) {

  const block = match[2] || "";

  // ---------- Scene number ----------
  const sceneNumMatch = block.match(
    /^\s*SCENE:\s*(?:Scene\s*)?([0-9]+)\s*$/im
  );
  const sceneNumber = cleanValue(sceneNumMatch?.[1] || "");

  // ---------- Narration ----------
  const narrMatch = block.match(
    /^\s*NARR:\s*([\s\S]*?)(?=^\s*TOS:\s*)/im
  );
  const narration = cleanValue(narrMatch?.[1] || "");

  // ---------- Text on Screen ----------
  const tosMatch = block.match(
    /^\s*TOS:\s*([\s\S]*)$/im
  );
  const tos = cleanValue(tosMatch?.[1] || "");

  // push result
  if (sceneNumber) {
    scenes.push({
      "Scene number": sceneNumber,
      "Narration": narration,
      "Text on Screen": tos,
    });
  }
}

// =============================
// RETURN OUTPUT
// =============================
return scenes.map(scene => ({ json: scene }));

// OPTIONAL:
// return [{ json: scenes }];

// Columns that can be replaced from translation
const REPLACE_COLS = [
  "Narration",
  "Text on Screen",
  "Visual Description"
];

const output = [];

// Loop through all input items
for (const item of $input.all()) {

  // Original row data
  const originalRow = item.json;

  // Make a copy so Scene number is preserved
  const mergedRow = { ...originalRow };

  // If you have translated values in the same item, use them
  const translationRow = item.json;

  // Replace only non-empty translated columns
  for (const col of REPLACE_COLS) {
    const newValue = translationRow[col];

    if (
      newValue !== undefined &&
      newValue !== null &&
      String(newValue).trim() !== "" &&
      String(newValue).toLowerCase() !== "empty"
    ) {
      mergedRow[col] = newValue;
    }
  }

  // IMPORTANT: ensure Scene number stays
  mergedRow["Scene number"] = originalRow["Scene number"];

  output.push({ json: mergedRow });
}

return output;

// ==========================
// EXTRACT VALUES FROM WEBHOOK
// ==========================
const TextBox = $input.first().json.body.TextBox || "";
const subject = $input.first().json.body.subject || "";
const grade   = $input.first().json.body.grade || "";
const referenceBox = $input.first().json.body.referenceText|| "";

// ==========================
// BUILD FINAL PROMPT
// ==========================
const prompt = `
You are an Expert Academic Curator and Translator.

Your primary goal is to create a factually correct, clear, and educationally sound learning module in Hindi.
Your responsibility is to produce a flawless final product, not just a literal translation.

Translate ONLY the content between the markers:
<<<START>>>
and
<<<END>>>

Do NOT translate anything outside these markers.
Do NOT add explanations.
Output ONLY the final translated Hindi text.

Subject: ${subject}
Grade: ${grade}
📘 NCERT Terminology Reference:
Below is the official reference terminology extracted from NCERT or curriculum guidelines.
You MUST strictly follow this terminology when translating.
If any term in the source text appears in this reference,
use the exact Hindi terminology from this reference.

Reference Box Content:
${referenceBox}

🔬 Core Principle: Correctness Over Literalism
Your primary duty is to the final learner, not the source text.
Prioritize factual, logical, and scientific accuracy over word-for-word translation.

If the English source contains a clear factual, logical, or numerical error,
correct it in the Hindi translation.

✍️ Tone & Style
• Use clear, natural Hindi like a teacher explaining to a student.
• Use short, simple sentences suitable for Grade ${grade}.
• Translate ideas, not just words.
• Avoid literal structural translation.

🧩 Terminology & Grammar
• Use correct standard textbook terminology for ${subject}.
• Maintain terminology consistency.
• Transliterate commonly used technical English terms.
• Maintain sentence-to-sentence correspondence.
• Follow natural Hindi word order (Subject → Object → Verb).

<<<START>>>
${TextBox}
<<<END>>>
`;

// ==========================
// RETURN GEMINI API FORMAT
// ==========================
return [
  {
    json: {
      contents: [
        {
          parts: [
            {
              text: prompt
            }
          ]
        }
      ]
    }
  }
];

// Get translated Hindi text from previous node
// ⚠️ IMPORTANT: adjust field if needed after checking AI output
const translatedText =
  $json.output ||
  $json.text ||
  $json.response ||
  "";

// File name from frontend
const fileName = $json.sheetNameOrId || "Simulation_File";

// Clean HTML entities if present
const cleanText = translatedText
  .replace(/&#39;/g, "'")
  .replace(/&amp;/g, "&")
  .replace(/&lt;/g, "<")
  .replace(/&gt;/g, ">");

// Convert to binary
const buffer = Buffer.from(cleanText, "utf-8");

return [
  {
    json: {
      fileName: fileName + ".docx"
    },
    binary: {
      data: {
        data: buffer.toString("base64"),
        mimeType:
          "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        fileName: fileName + ".docx"
      }
    }
  }
];
